<div className="relative min-h-[100vh] flex flex-col justify-center items-center overflow-x-hidden py-10 px-4 md:px-8">
  <video
    className="absolute top-0 left-0 w-full h-full object-cover"
    autoPlay
    loop
    muted
    playsInline
    src="/globe.mp4"
  />
  <div className="absolute top-0 left-0 w-full h-full bg-black/70"></div>

  <main className="relative z-10 w-full max-w-[1200px] flex flex-col items-center">
    <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center w-full mb-8 gap-4">
      <h1 className="text-3xl md:text-4xl font-bold text-white text-center sm:text-left">
        Kosovo Air Quality
      </h1>

      <div className="flex gap-2">
        <input
          type="text"
          placeholder="Search city..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="px-4 py-2 rounded-full focus:outline-none text-sm sm:text-base"
        />

        <button
          onClick={toggleTheme}
          className="p-3 rounded-full flex items-center justify-center hover:opacity-90 transition-all"
        >
          {theme === "light" ? (
            <MoonIcon className="w-4 h-4" />
          ) : (
            <SunIcon className="w-4 h-4" />
          )}
        </button>
      </div>
    </div>

    {error && <p className="text-red-600 mb-4 text-center">{error}</p>}

    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4 w-full justify-items-center">
      {noCityFound ? (
        <p className="text-white text-center w-full col-span-full">
          Sorry, this city is not supported yet
        </p>
      ) : (
        filteredCities.map((cityKey) => (
          <AQICard
            key={cityKey}
            city={cityMapping[cityKey]}
            data={data[cityKey]}
            loading={loading}
          />
        ))
      )}
    </div>

    <div className="mt-6 text-center w-full">
      <p className="text-white text-xs md:text-sm opacity-80 mx-auto">
        AQI (Air Quality Index) shows how clean or polluted the air is. Dominant
        pollutant indicates the particle or gas (PM2.5, PM10, NO2, O3)
        contributing most to the current pollution.
      </p>
    </div>
  </main>
</div>;
